import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'https://zpkyjsvpahckjgkqhdej.supabase.co';
const supabaseAnonKey = 'sb_publishable_mCzzuVHM-IUxjT2AH4uBWA_23HPemKw';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useEffect } from 'react';
import { HomePage } from './components/HomePage';
import { WelcomePage } from './components/WelcomePage';
import { GlobePage } from './components/GlobePage';
import { AboutPage } from './components/AboutPage';
import { ContactPage } from './components/ContactPage';
import { ChatBot } from './components/ChatBot';
import { ImageAnalysisPage } from './components/ImageAnalysisPage';
import { CheckupPage } from './components/CheckupPage';
import { PrescriptionAnalysisPage } from './components/PrescriptionAnalysisPage';
import { IntroAnimation } from './components/IntroAnimation';
import { MentalHealthPage } from './components/MentalHealthPage';
import { SymptomCheckerPage } from './components/SymptomCheckerPage';
import { AuthPage } from './components/AuthPage';
import { ActivityHistoryPage } from './components/ActivityHistoryPage';
import type { User, ActivityLogItem, Page } from './types';
import { HealthForecast } from './components/HealthForecast';
import { AdminDashboardPage } from './components/AdminDashboardPage';
import { ProfilePage } from './components/ProfilePage';
import { Sidebar } from './components/Sidebar';
import { AlertsPage } from './components/AlertsPage';
import { WaterLogPage } from './components/WaterLogPage';
import { Bars3Icon, GlobeIcon } from './components/icons';
import { FeedbackModal } from './components/FeedbackModal';
import { I18nProvider } from './components/I18n';
import { supabase } from './services/supabaseClient';

const ACTIVITY_HISTORY_KEY = 'geosick_activity_history';
const GLOBAL_ACTIVITY_HISTORY_KEY = 'geosick_global_activity_history';

function AppContent() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [showIntro, setShowIntro] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [showAuth, setShowAuth] = useState(false);
  const [activityHistory, setActivityHistory] = useState<ActivityLogItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFeedbackModalOpen, setIsFeedbackModalOpen] = useState(false);

  useEffect(() => {
    // Check Supabase session on mount
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        fetchUserProfile(session.user.id);
      }
    });

    // Listen for auth state changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        fetchUserProfile(session.user.id);
      } else {
        setUser(null);
        setCurrentPage('home');
      }
    });

    // Load personal activity history from local cache for speed (optional)
    try {
      const storedHistory = localStorage.getItem(ACTIVITY_HISTORY_KEY);
      if (storedHistory) {
          setActivityHistory(JSON.parse(storedHistory));
      }
    } catch (error) {
        console.error("Could not load activity history:", error);
    }

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (data) {
        setUser({
          id: data.id,
          phone: data.phone,
          name: data.full_name,
          email: data.email,
          date_of_birth: data.dob,
          gender: data.gender,
          place: data.place,
          created_at: data.created_at,
          last_login_at: data.last_login_at,
          isAdmin: data.is_admin,
        });
        if (currentPage === 'home') setCurrentPage('welcome');
      }
    } catch (err) {
      console.error("Error fetching profile:", err);
    }
  };

  const addGlobalActivityToHistory = (item: ActivityLogItem) => {
      try {
          const globalHistory: ActivityLogItem[] = JSON.parse(localStorage.getItem(GLOBAL_ACTIVITY_HISTORY_KEY) || '[]');
          const newGlobalHistory = [item, ...globalHistory];
          localStorage.setItem(GLOBAL_ACTIVITY_HISTORY_KEY, JSON.stringify(newGlobalHistory));
      } catch (error) {
           console.error("Could not save global activity:", error);
      }
  };

  const addActivityToHistory = (item: Omit<ActivityLogItem, 'id' | 'timestamp' | 'userPhone'>) => {
      if (!user) return;
      const newActivity: ActivityLogItem = {
          ...item,
          id: new Date().toISOString() + Math.random(),
          timestamp: Date.now(),
          userPhone: user.phone,
      };

      setActivityHistory(prevHistory => {
          const newHistory = [newActivity, ...prevHistory];
          try {
            localStorage.setItem(ACTIVITY_HISTORY_KEY, JSON.stringify(newHistory));
          } catch (error) {
              console.error("Could not save activity history:", error);
          }
          return newHistory;
      });

      addGlobalActivityToHistory(newActivity);
  };

  const handleUpdateUser = async (updatedDetails: Partial<User>) => {
    if (!user?.id) return false;

    try {
        const { error } = await supabase
          .from('profiles')
          .update({
            full_name: updatedDetails.name,
            email: updatedDetails.email,
            place: updatedDetails.place,
            gender: updatedDetails.gender,
          })
          .eq('id', user.id);

        if (error) throw error;

        await fetchUserProfile(user.id);
        return true;
    } catch (error) {
        console.error("Failed to update user:", error);
        return false;
    }
  };

  const handleAuthSuccess = (authedUser: User) => {
    setUser(authedUser);
    setShowAuth(false);
    setCurrentPage('welcome');
  };

  const handleLogout = async () => {
      await supabase.auth.signOut();
      setUser(null);
      setCurrentPage('home');
      setIsFeedbackModalOpen(false);
  };

  const handleNavigation = (page: Page) => {
      setCurrentPage(page);
  };

  const renderPublicPages = () => {
    switch (currentPage) {
        case 'about':
            return <AboutPage onBack={() => setCurrentPage('home')} />;
        case 'contact':
            return <ContactPage onBack={() => setCurrentPage('home')} />;
        case 'explore':
             return <GlobePage onBack={() => setCurrentPage('home')} />;
        case 'home':
        default:
            return <HomePage
                onLoginClick={() => setShowAuth(true)}
                onAboutClick={() => setCurrentPage('about')}
                onContactClick={() => setCurrentPage('contact')}
                onExploreClick={() => setCurrentPage('explore')}
            />;
    }
  }

  const renderAuthenticatedApp = () => {
    if (!user) return null;

    const renderPage = () => {
        const isAdmin = !!user.isAdmin;
        switch (currentPage) {
            case 'welcome':
            case 'home':
                return <WelcomePage
                    user={user}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
            case 'live-alerts':
                return <AlertsPage />;
            case 'image-analysis':
                return <ImageAnalysisPage
                    onBack={() => setCurrentPage('welcome')}
                    onScheduleCheckup={() => setCurrentPage('checkup')}
                    onAnalysisComplete={addActivityToHistory}
                />;
            case 'prescription-analysis':
                return <PrescriptionAnalysisPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={addActivityToHistory} />;
            case 'checkup':
                return <CheckupPage onBack={() => setCurrentPage('image-analysis')} />;
            case 'mental-health':
                return <MentalHealthPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={addActivityToHistory} />;
            case 'symptom-checker':
                return <SymptomCheckerPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={addActivityToHistory} />;
            case 'health-briefing': 
                 return <HealthForecast onBack={() => setCurrentPage('welcome')} />;
            case 'activity-history':
                 return <ActivityHistoryPage history={activityHistory} onBack={() => setCurrentPage('welcome')} />;
            case 'profile':
                return <ProfilePage user={user} onBack={() => setCurrentPage('welcome')} onUpdateUser={handleUpdateUser} />;
            case 'water-log':
                return <WaterLogPage onBack={() => setCurrentPage('welcome')} />;
            case 'admin-dashboard':
                return isAdmin ? <AdminDashboardPage onBack={() => setCurrentPage('welcome')} /> : <p>Access Denied.</p>;
            case 'about':
                 return <AboutPage onBack={() => setCurrentPage('welcome')} />;
            case 'contact':
                return <ContactPage onBack={() => setCurrentPage('welcome')} />;
            case 'explore':
                return <GlobePage onBack={() => setCurrentPage('welcome')} />;
            default:
                return <WelcomePage
                    user={user}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
        }
    };

    return (
        <div className="flex h-screen bg-slate-100">
            <Sidebar 
                user={user} 
                currentPage={currentPage} 
                onNavigate={(page: Page) => {
                    handleNavigation(page);
                    setIsSidebarOpen(false);
                }} 
                onLogout={handleLogout}
                isOpen={isSidebarOpen}
                onClose={() => setIsSidebarOpen(false)}
                onOpenFeedbackModal={() => setIsFeedbackModalOpen(true)}
            />
             <div className="flex-1 flex flex-col">
                <header className="md:hidden bg-white border-b border-slate-200 p-4 flex items-center justify-between shadow-sm relative z-20">
                    <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 p-1" aria-label="Open menu">
                        <Bars3Icon className="w-6 h-6" />
                    </button>
                    <div className="flex items-center gap-2">
                        <GlobeIcon className="w-7 h-7 text-blue-500" />
                        <h1 className="text-lg font-bold tracking-tight text-slate-800">GeoSick</h1>
                    </div>
                    <div className="w-7"></div>
                </header>
                <main className="flex-1 overflow-y-auto">
                    {renderPage()}
                </main>
            </div>
        </div>
    );
  };

  if (showIntro) {
    return <IntroAnimation onComplete={() => setShowIntro(false)} />;
  }

  return (
    <>
      {user ? renderAuthenticatedApp() : renderPublicPages()}
      {user && <ChatBot onNavigate={handleNavigation} />}
      {user && isFeedbackModalOpen && (
        <FeedbackModal 
            user={user}
            onClose={() => setIsFeedbackModalOpen(false)} 
        />
      )}
      {showAuth && (
        <AuthPage
          onClose={() => setShowAuth(false)}
          onAuthSuccess={handleAuthSuccess}
        />
      )}
    </>
  );
}

export default function App() {
    return (
        <I18nProvider>
            <AppContent />
        </I18nProvider>
    );
}

import React, { useState } from 'react';
import { CloseIcon, GlobeIcon, PhoneIcon, LockClosedIcon, UserIcon, CalendarIcon, AtSymbolIcon } from './icons';
import RotatingGlobe from './RotatingGlobe';
import type { User } from '../types';
import { supabase } from '../services/supabaseClient';

interface AuthPageProps {
  onClose: () => void;
  onAuthSuccess: (user: User) => void;
}

type ViewMode = 'login' | 'signup';

export const AuthPage: React.FC<AuthPageProps> = ({ onClose, onAuthSuccess }) => {
  const [viewMode, setViewMode] = useState<ViewMode>('login');

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [dateOfBirth, setDateOfBirth] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginIdentifier, setLoginIdentifier] = useState(''); // Email or Phone
  const [email, setEmail] = useState('');
  const [gender, setGender] = useState('');
  const [place, setPlace] = useState('');

  const [error, setError] = useState<string>('');
  const [infoMessage, setInfoMessage] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);

  const resetForms = () => {
    setPhone('');
    setPassword('');
    setError('');
    setName('');
    setDateOfBirth('');
    setConfirmPassword('');
    setInfoMessage('');
    setLoginIdentifier('');
    setEmail('');
    setGender('');
    setPlace('');
  }

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
        const identifier = loginIdentifier.trim();
        // Supabase Auth logic
        const { data, error: authError } = await supabase.auth.signInWithPassword({
            email: identifier.includes('@') ? identifier : `${identifier}@geosick.placeholder`,
            password: password,
        });

        if (authError) throw authError;

        if (data.user) {
            const { data: profile } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', data.user.id)
                .single();

            if (profile) {
                onAuthSuccess({
                    id: profile.id,
                    phone: profile.phone,
                    name: profile.full_name,
                    email: profile.email,
                    date_of_birth: profile.dob,
                    gender: profile.gender,
                    place: profile.place,
                    created_at: profile.created_at,
                    isAdmin: profile.is_admin,
                });
            }
        }
    } catch (err: any) {
        console.error("Login error:", err);
        setError(err.message || "Invalid credentials.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (password !== confirmPassword) {
        setError("Passwords do not match.");
        return;
    }
    if (!name.trim() || (!phone.trim() && !email.trim()) || !dateOfBirth || !password) {
        setError("Please fill out all required fields.");
        return;
    }
    setIsLoading(true);

    try {
        const signupEmail = email.trim() || `${phone.trim()}@geosick.placeholder`;

        const { data, error: signupError } = await supabase.auth.signUp({
            email: signupEmail,
            password: password,
        });

        if (signupError) throw signupError;

        if (data.user) {
            // Create user profile in profiles table
            const { error: profileError } = await supabase
                .from('profiles')
                .insert({
                    id: data.user.id,
                    full_name: name.trim(),
                    email: email.trim() || null,
                    phone: phone.trim() || null,
                    dob: dateOfBirth,
                    gender: gender || null,
                    place: place.trim() || null,
                });

            if (profileError) throw profileError;

            onAuthSuccess({
                id: data.user.id,
                phone: phone.trim(),
                name: name.trim(),
                email: email.trim() || null,
                date_of_birth: dateOfBirth,
                gender: gender || null,
                place: place.trim() || null,
                created_at: new Date().toISOString(),
            });
        }

    } catch (err: any) {
         console.error("Sign up error:", err);
         setError(err.message || "An error occurred during signup.");
    } finally {
         setIsLoading(false);
    }
  };

  const inputClasses = "w-full pl-11 pr-3 py-3 bg-white border border-slate-300 rounded-md placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-blue-500 focus:border-blue-500 transition-shadow";
  const buttonClasses = "w-full bg-blue-500 hover:bg-blue-600 text-white font-semibold py-3 px-4 rounded-md transition-all duration-300 shadow-sm hover:shadow-md disabled:bg-slate-400 disabled:cursor-not-allowed";

  const renderSignUpForm = () => (
     <form onSubmit={handleSignUp} className="space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
                <label htmlFor="name-signup" className="sr-only">Full Name</label>
                <div className="relative">
                    <UserIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input id="name-signup" type="text" value={name} onChange={(e) => setName(e.target.value)} required className={inputClasses} placeholder="Full Name *" />
                </div>
            </div>
            <div>
                <label htmlFor="phone-signup" className="sr-only">Phone Number</label>
                <div className="relative">
                    <PhoneIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input id="phone-signup" type="tel" value={phone} onChange={(e) => setPhone(e.target.value)} required className={inputClasses} placeholder="Phone Number *" />
                </div>
            </div>
        </div>
        <div>
            <label htmlFor="email-signup" className="sr-only">Email Address</label>
            <div className="relative">
                <AtSymbolIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input id="email-signup" type="email" value={email} onChange={(e) => setEmail(e.target.value)} className={inputClasses} placeholder="Email Address (Optional)" />
            </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
                <label htmlFor="dob" className="sr-only">Date of Birth</label>
                <div className="relative">
                    <CalendarIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input id="dob" type="date" value={dateOfBirth} onChange={(e) => setDateOfBirth(e.target.value)} required className={inputClasses} placeholder="Date of Birth *" />
                </div>
            </div>
            <div>
                <label htmlFor="place-signup" className="sr-only">Place</label>
                <div className="relative">
                    <GlobeIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input id="place-signup" type="text" value={place} onChange={(e) => setPlace(e.target.value)} className={inputClasses} placeholder="Place (Optional)" />
                </div>
            </div>
        </div>
        <div>
             <label htmlFor="gender-signup" className="sr-only">Gender</label>
             <select id="gender-signup" value={gender} onChange={(e) => setGender(e.target.value)} className={`${inputClasses} pl-4`}>
                <option value="">Select Gender (Optional)</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
                <option value="Prefer not to say">Prefer not to say</option>
            </select>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
                <label htmlFor="password-signup" className="sr-only">Password</label>
                <div className="relative">
                    <LockClosedIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input id="password-signup" type="password" value={password} onChange={(e) => setPassword(e.target.value)} required className={inputClasses} placeholder="Password *" />
                </div>
            </div>
             <div>
                <label htmlFor="confirm-password-signup" className="sr-only">Confirm Password</label>
                <div className="relative">
                    <LockClosedIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input id="confirm-password-signup" type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} required className={inputClasses} placeholder="Confirm Password *" />
                </div>
            </div>
        </div>
        <button type="submit" disabled={isLoading} className={buttonClasses}>
            {isLoading ? 'Creating Account...' : 'Create Account'}
        </button>
    </form>
  );

  const renderLoginForm = () => (
    <form onSubmit={handleLogin} className="space-y-4">
        <div>
            <label htmlFor="login-identifier" className="sr-only">Phone Number or Email</label>
            <div className="relative">
                <AtSymbolIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input id="login-identifier" type="text" value={loginIdentifier} onChange={(e) => setLoginIdentifier(e.target.value)} required className={inputClasses} placeholder="Phone or Email" />
            </div>
        </div>
        <div>
            <label htmlFor="password-input" className="sr-only">Password</label>
            <div className="relative">
                <LockClosedIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                <input id="password-input" type="password" value={password} onChange={(e) => setPassword(e.target.value)} required className={inputClasses} placeholder="Password" />
            </div>
        </div>
        <div className="text-right">
            <button type="button" className="text-sm text-blue-600 hover:underline font-medium">
                Forgot Password?
            </button>
        </div>
        <button type="submit" disabled={isLoading} className={buttonClasses}>
            {isLoading ? 'Logging In...' : 'Login Securely'}
        </button>
    </form>
  );


  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md lg:max-w-4xl flex flex-col lg:grid lg:grid-cols-2 animate-fade-in-up overflow-hidden max-h-[90vh] lg:max-h-none">
        <div className="flex flex-col items-center justify-center p-8 lg:p-12 bg-gradient-to-br from-blue-600 to-slate-800 text-white relative order-first">
            <div className="absolute inset-0 z-0 h-full w-full opacity-50"><RotatingGlobe /></div>
            <div className="z-10 text-center">
                <GlobeIcon className="w-16 h-16 lg:w-20 lg:h-20 text-white mx-auto mb-4"/>
                <h2 className="text-2xl lg:text-3xl font-bold">GeoSick</h2>
                <p className="mt-2 text-blue-200 text-sm lg:text-base">AI-Powered Environmental Health Intelligence.</p>
            </div>
        </div>
        <div className="p-8 sm:p-12 relative overflow-y-auto">
            <button onClick={onClose} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 z-10" aria-label="Close authentication"><CloseIcon className="w-6 h-6" /></button>
            <div className="w-full flex border-b border-slate-200 mb-8">
                 <button onClick={() => { setViewMode('login'); resetForms(); }} className={`flex-1 text-center font-semibold pb-3 border-b-2 transition-colors ${viewMode === 'login' ? 'text-slate-800 border-blue-500' : 'text-slate-400 border-transparent hover:border-slate-300'}`}>
                    Login
                </button>
                 <button onClick={() => { setViewMode('signup'); resetForms(); }} className={`flex-1 text-center font-semibold pb-3 border-b-2 transition-colors ${viewMode === 'signup' ? 'text-slate-800 border-blue-500' : 'text-slate-400 border-transparent hover:border-slate-300'}`}>
                    Sign Up
                </button>
            </div>

            {viewMode === 'login' && (
                <div className="animate-fade-in">
                    <h2 className="text-2xl font-bold text-slate-900">Welcome Back</h2>
                    <p className="text-slate-500 mt-1 mb-6">Login to access your dashboard.</p>
                    {renderLoginForm()}
                </div>
            )}

            {viewMode === 'signup' && (
                <div className="animate-fade-in">
                    <h2 className="text-2xl font-bold text-slate-900">Create an Account</h2>
                     {infoMessage ? (
                         <p className="text-sm text-blue-700 bg-blue-50 p-3 rounded-md mt-1 mb-6">{infoMessage}</p>
                    ) : (
                        <p className="text-slate-500 mt-1 mb-6">Get started with GeoSick's full suite of tools.</p>
                    )}
                    {renderSignUpForm()}
                </div>
            )}

            {error && <div className="text-sm text-red-600 text-center pt-4">{error}</div>}
        </div>
      </div>
    </div>
  );
};

export type Page =
  | 'home'
  | 'welcome'
  | 'image-analysis'
  | 'prescription-analysis'
  | 'checkup'
  | 'mental-health'
  | 'symptom-checker'
  | 'about'
  | 'contact'
  | 'explore'
  | 'live-alerts'
  | 'health-briefing'
  | 'activity-history'
  | 'profile'
  | 'admin-dashboard'
  | 'water-log';

export interface User {
  id?: string;
  phone: string;
  name: string;
  email?: string | null;
  date_of_birth?: string | null;
  gender?: string | null;
  place?: string | null;
  created_at?: string | null;
  last_login_at?: string | null;
  password?: string;
  isAdmin?: boolean;
}

export interface ActivityLogItem {
  id: string;
  timestamp: number;
  userPhone: string;
