    setIsLoading(true);

    try {
        // Supabase requires an email. If user provides phone, we generate a placeholder.
        const signupEmail = email.trim() || `${phone.trim()}@geosick.placeholder`;

        const { data, error: signupError } = await supabase.auth.signUp({
            email: signupEmail,
            password: password,
            options: {
                data: {
                    full_name: name.trim(),
                }
            }
        });

        if (signupError) throw signupError;

        if (data.user) {
            // Important: We must insert the profile details into the public.profiles table
            const { error: profileError } = await supabase
                .from('profiles')
                .insert({
