const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

async function callGeminiWithRetry<T>(
    apiCall: () => Promise<T>,
    maxRetries: number = 3,
    initialDelay: number = 1000
): Promise<T> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            return await apiCall();
        } catch (error: any) {
            const isRateLimitError = error.toString().includes('429') || error.toString().includes('RESOURCE_EXHAUSTED');
            if (isRateLimitError && attempt < maxRetries - 1) {
                const delay = initialDelay * Math.pow(2, attempt);
                await sleep(delay);
                attempt++;
            } else {
                throw error;
            }
        }
    }
    throw new Error('Exceeded maximum retries.');
}

/**
 * STRICT recursive string extractor to prevent React Error #31.
 * This guarantees that we NEVER pass an object to a React child.
 */
export const safeString = (val: any, fallback: string = ''): string => {
    if (typeof val === 'string') return val;
    if (val === null || val === undefined) return fallback;

    if (typeof val === 'object') {
        // High-priority keys for labels commonly returned by geocoding
        const keys = ['name', 'label', 'cityName', 'locationName', 'area', 'address', 'fullAddress', 'description', 'city', 'state', 'district'];
        for (const key of keys) {
            if (val[key] && typeof val[key] === 'string') {
                return val[key];
            } else if (val[key] && typeof val[key] === 'object') {
                const nested = safeString(val[key]);
                if (nested) return nested;
            }
        }

        // If it's a coordinate object, don't use it as a label string
        if (typeof val.lat === 'number' || typeof val.lng === 'number') return fallback;

        // Fallback to stringification for unknown structures
        try {
            return JSON.stringify(val);
        } catch {
            return fallback;
        }
    }
    return String(val);
};

