                    action: { type: Type.STRING, enum: ["navigate", "speak"] },
                    page: { type: Type.STRING },
                    responseText: { type: Type.STRING }
                },
                required: ["action", "responseText"]
            }
        }
    });
    return JSON.parse(cleanJsonString(response.text || '{}'));
};

